external_knowledge:
- "stand above the ordinary wave" metaphorically refers to sellers with sales figures surpassing the average;
- "sailing through the turbulent sea of commerce" is a metaphor for operating in the challenging market;
- "haul in their sails" symbolizes the total sales amount they have achieved.

sql:
SELECT buyer_name, buyer_since
FROM buyers
WHERE buyer_id IN (
    SELECT buyer_id
    FROM sales
    WHERE sale_date = (
        SELECT MAX(sale_date)
        FROM sales
    )
);

SELECT parcel_id, size
FROM parcels
WHERE size > 100000;

SELECT parcel_type, land_use
FROM parcels
WHERE size > (SELECT AVG(size) FROM parcels);

SELECT parcel_id, size
FROM parcels
WHERE size > (SELECT MIN(size) FROM parcels);

SELECT COUNT(*) AS number_of_buyers, buyer_type, buyer_name
FROM buyers
WHERE buyer_type = 'settler' AND buyer_name = 'Sulpicians';

SELECT COUNT(*) AS TotalParcels
FROM parcels
WHERE parcel_type = 'Commercial' AND year = 1780;

SELECT p.*
FROM parcels p
JOIN sales s ON p.parcel_id = s.parcel_id
WHERE s.total = (
    SELECT MAX(total) FROM sales
);

SELECT s.sale_id, s.totalS
FROM sales s
INNER JOIN sellers sel ON s.seller_id = sel.seller_id;
